<script setup lang="ts">
import {computed,ref} from 'vue';
type Option={label:string,value:string|Record<string,unknown>,group?:string};const props=withDefaults(defineProps<{label?:string;size?:'xs'|'sm'|'base'|'lg';variant?:string;loading?:boolean;disabled?:boolean;modelValue?:string|Record<string,unknown>;options?:Option[]}>(),{label:'Fruit',size:'base',variant:'default',options:()=>[{label:'Apple',value:{id:1},group:'Popular'},{label:'Banana',value:'banana',group:'Popular'},{label:'Cherry',value:'cherry',group:'Other'}]});const open=ref(false),active=ref(0),value=ref(props.modelValue);const label=computed(()=>props.options.find(x=>x.value===value.value)?.label??'Choose fruit');function choose(i:number){value.value=props.options[i].value;active.value=i;open.value=false}function key(e:KeyboardEvent){if(props.disabled||props.loading)return;const last=props.options.length-1;if(e.key==='Escape'){open.value=false;return}if(e.key==='Home')active.value=0;else if(e.key==='End')active.value=last;else if(e.key==='ArrowDown')active.value=Math.min(last,active.value+1);else if(e.key==='ArrowUp')active.value=Math.max(0,active.value-1);else if((e.key==='Enter'||e.key===' ')&&open.value){choose(active.value);e.preventDefault();return}else return;e.preventDefault();open.value=true}
</script>
<template><main class="shell"><h1>Select</h1><section class="matrix"><div class="kumo-field"><label for="rich-select">{{label}}</label><button id="rich-select" role="combobox" aria-haspopup="listbox" aria-controls="rich-options" :aria-expanded="open" :aria-activedescendant="open?'option-'+active:undefined" :aria-busy="loading||undefined" :disabled="disabled||loading" :class="['kumo-trigger',size,variant]" @click="open=!open" @keydown="key"><span>{{loading?'Loading…':label}}</span></button><ul v-if="open" id="rich-options" role="listbox"><template v-for="(group) in [...new Set(options.map(x=>x.group))]" :key="group"><li role="presentation"><strong>{{group}}</strong></li><li v-for="(option,i) in options.filter(x=>x.group===group)" :id="'option-'+options.indexOf(option)" :key="option.label" role="option" :aria-selected="option.value===value" :class="{active:options.indexOf(option)===active}" @pointerdown.prevent="choose(options.indexOf(option))">{{option.label}}</li></template></ul></div></section></main></template>
